def topla_bit_operasyonlariyla(sayi1, sayi2):
    MASK = 0xFFFFFFFF  # 32-bit unsigned tam sayı maskesi
    MAX_INT = 0x7FFFFFFF # En büyük 32-bit işaretli tam sayı

    while sayi2 != 0:
        # XOR işlemi, taşıma olmadan toplama yapar (sum)
        # AND işlemi ve sola kaydırma, bir sonraki adım için taşımayı hesaplar (carry)
        sayi1, sayi2 = (sayi1 ^ sayi2) & MASK, ((sayi1 & sayi2) << 1) & MASK

    # Döngü bittiğinde, sayi1 değeri 32-bit işaretlenmemiş formatta toplamı tutar.
    # Eğer sayı negatif ise (yani en yüksek bit set ise), Python'ın işaretli tamsayı formatına dönüştürmeliyiz.
    if sayi1 > MAX_INT:
        return ~(sayi1 ^ MASK)
    else:
        return sayi1
